function isEmpty(source) {
    // Checks for null, undefined, not an array, or empty array
    return !Array.isArray(source) || source.length === 0;
}


logger.error("Source appname: " + JSON.stringify(source));
//if(!isEmpty(source)){
if(!source == null || !source == ""){
var sourceAppId = source._refResourceId;
logger.error("sourceAppId ref: "+sourceAppId);

try {

    var appNameResponse = openidm.query(
        "managed/alpha_kyid_businessapplication",{
             "_queryFilter": '_id eq "' + sourceAppId + '"'
        },
        ["name"]
    );
    logger.error("App Response: " + JSON.stringify(appNameResponse));

    if (appNameResponse.result && appNameResponse.result.length == 1) {

		var appName = appNameResponse.result[0].name;
		logger.error("appName in response : "+appName);

    } else {
		logger.error("Exception occurred during role to app link " );
    }
} catch (e) {
    logger.error("Exception occurred: " + e);  
}
appName;
}else{
	null;
}
